<span class="line">    <span class="token keyword">let</span> init<span class="token punctuation">:</span> <span class="token class-name">Message</span> <span class="token operator">=</span> <span class="token namespace">msg<span class="token punctuation">::</span></span><span class="token function">load</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">expect</span><span class="token punctuation">(</span><span class="token string">&quot;Unable to decode Message&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
